#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;

vector<int> g[N];
int up[N][20], dep[N], mx[N];

void dfs(int u, int p) {
    up[u][0] = p;
    dep[u] = dep[p] + 1;
    mx[u] = max(u, mx[p]);
    for (int i = 1; i < 20; i++)
        up[u][i] = up[up[u][i-1]][i-1];
    for (int v : g[u]) {
        if (v != p) dfs(v, u);
    }
}

int lca(int x, int y) {
    if (dep[x] < dep[y]) swap(x, y);
    int diff = dep[x] - dep[y];
    for (int i = 0; i < 20; i++)
        if (diff >> i & 1) x = up[x][i];
    if (x == y) return x;
    for (int i = 19; i >= 0; i--)
        if (up[x][i] != up[y][i])
            x = up[x][i], y = up[y][i];
    return up[x][0];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    for (int i = 1; i < n; i++) {
        int f;
        cin >> f;
        g[f].push_back(i);
        g[i].push_back(f);
    }

    mx[0] = 0;
    dfs(0, 0);

    int q;
    cin >> q;
    while (q--) {
        int m;
        cin >> m;
        int l = -1;
        for (int i = 0; i < m; i++) {
            int x;
            cin >> x;
            if (l == -1) l = x;
            else l = lca(l, x);
        }
        cout << mx[l] << '\n';
    }

    return 0;
}
